SELECT o.*, p.content, u.name AS user_name
FROM feed_outbox o
JOIN feed_post p ON o.post_id = p.id
JOIN `user` u ON o.user_id = u.id
WHERE o.user_id = #{userId}
AND (p.visible_until IS NULL OR p.visible_until > NOW())

    AND o.id < #{cursor}

ORDER BY o.created_at DESC
LIMIT #{size}

